using System;
using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Shared test infrastructure for creating in-memory SchoolContext instances.
/// </summary>
public static class TestHelpers
{
    /// <summary>
    /// Creates a fresh SchoolContext backed by an in-memory database.
    /// Each call with a unique name gives an isolated database.
    /// </summary>
    public static SchoolContext CreateInMemoryContext(string? dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }
}

