using System;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_WhenBothNamesSet_ReturnsLastNameCommaFirstName()
    {
        // Arrange - Person is abstract, use Student as concrete type
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    public void FullName_WithInstructor_ReturnsLastNameCommaFirstName()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = DateTime.Parse("2020-01-01")
        };

        // Act
        var result = instructor.FullName;

        // Assert
        Assert.AreEqual("Abercrombie, Kim", result);
    }

    [TestMethod]
    [DataRow("", "John", ", John", DisplayName = "Empty last name")]
    [DataRow("Smith", "", "Smith, ", DisplayName = "Empty first name")]
    public void FullName_EdgeCases_ReturnsExpectedFormat(string lastName, string firstName, string expected)
    {
        // Arrange
        var student = new Student { LastName = lastName, FirstMidName = firstName };

        // Act & Assert
        Assert.AreEqual(expected, student.FullName);
    }

    [TestMethod]
    public void ID_DefaultsToZero()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.AreEqual(0, student.ID);
    }

    [TestMethod]
    public void ID_CanBeSet()
    {
        // Arrange & Act
        var student = new Student { ID = 42 };

        // Assert
        Assert.AreEqual(42, student.ID);
    }
}

