using System;
using System.Collections.Generic;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class NotificationModelTests
{
    [TestMethod]
    public void Notification_PropertiesRoundTrip()
    {
        // Arrange
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New Student created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = false,
            ReadAt = null
        };

        // Assert
        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student created", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void Notification_IsRead_CanBeSetToTrue()
    {
        // Arrange
        var readTime = DateTime.Now;
        var notification = new Notification
        {
            Id = 2,
            EntityType = "Course",
            EntityId = "100",
            Operation = "UPDATE",
            Message = "Course updated",
            CreatedAt = DateTime.Now.AddMinutes(-5),
            IsRead = true,
            ReadAt = readTime
        };

        // Assert
        Assert.IsTrue(notification.IsRead);
        Assert.AreEqual(readTime, notification.ReadAt);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "CREATE")]
    [DataRow(EntityOperation.UPDATE, "UPDATE")]
    [DataRow(EntityOperation.DELETE, "DELETE")]
    public void EntityOperation_ToString_ReturnsExpectedValue(EntityOperation op, string expected)
    {
        // Act & Assert
        Assert.AreEqual(expected, op.ToString());
    }

    [TestMethod]
    public void EntityOperation_HasThreeValues()
    {
        // Act
        var values = Enum.GetValues<EntityOperation>();

        // Assert
        Assert.AreEqual(3, values.Length);
    }
}

