[TestClass]
public sealed class StudentModelTests
{
    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        // Arrange
        var date = new DateTime(2023, 9, 1);
        var student = new Student
        {
            LastName = "Doe",
            FirstMidName = "Jane",
            EnrollmentDate = date
        };

        // Assert
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void Student_Enrollments_DefaultsToNull()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.IsNull(student.Enrollments);
    }

    [TestMethod]
    public void Student_Enrollments_CanBeInitialized()
    {
        // Arrange
        var student = new Student
        {
            Enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, CourseID = 100, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 200, StudentID = 1, Grade = Grade.B }
            }
        };

        // Assert
        Assert.AreEqual(2, student.Enrollments.Count);
    }

    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        // Arrange & Act
        var student = new Student { ID = 5, LastName = "Test", FirstMidName = "User" };

        // Assert - verifies Person base class properties are accessible
        Assert.AreEqual(5, student.ID);
        Assert.AreEqual("Test, User", student.FullName);
    }
}

