using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndexAndTotalPages()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act - 10 total items, page 2, page size 3 => ceil(10/3) = 4 total pages
        var list = new PaginatedList<int>(items, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
        Assert.AreEqual(4, list.TotalPages);
        Assert.AreEqual(3, list.Count);
    }

    [TestMethod]
    public void Constructor_ContainsAllProvidedItems()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 3, 1, 10);

        // Assert
        CollectionAssert.AreEqual(items, list);
    }

    [TestMethod]
    [DataRow(1, false, DisplayName = "First page has no previous")]
    [DataRow(2, true, DisplayName = "Second page has previous")]
    [DataRow(3, true, DisplayName = "Third page has previous")]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        // Act & Assert
        Assert.AreEqual(expected, list.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 3, true, DisplayName = "First page of 3 has next")]
    [DataRow(2, 3, true, DisplayName = "Middle page of 3 has next")]
    [DataRow(3, 3, false, DisplayName = "Last page of 3 has no next")]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
    {
        // Arrange - pageSize=10, count=totalPages*10 so TotalPages = totalPages
        var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);

        // Assert
        Assert.AreEqual(expected, list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange - 15 items, page 2 of size 5 => items 6-10
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages); // ceil(15/5) = 3
        Assert.AreEqual(5, result.Count);
        CollectionAssert.AreEqual(new List<int> { 6, 7, 8, 9, 10 }, result);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.IsTrue(result.HasNextPage);
        Assert.IsFalse(result.HasPreviousPage);
        CollectionAssert.AreEqual(new List<int> { 1, 2, 3, 4, 5 }, result);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange - 12 items, page 3 of size 5 => items 11-12
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 5);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.IsFalse(result.HasNextPage);
        Assert.IsTrue(result.HasPreviousPage);
        CollectionAssert.AreEqual(new List<int> { 11, 12 }, result);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SinglePage_NoNextOrPrevious()
    {
        // Arrange - 3 items, page size 10 => single page
        var source = Enumerable.Range(1, 3).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
        Assert.AreEqual(3, result.Count);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly_WithExactDivision()
    {
        // 20 items / 5 per page = exactly 4 pages
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    public void TotalPages_RoundsUp_WithRemainder()
    {
        // 21 items / 5 per page = 5 pages (ceil)
        var list = new PaginatedList<int>(new List<int>(), 21, 1, 5);
        Assert.AreEqual(5, list.TotalPages);
    }
}

