namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2022, 1, 15) }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _sut.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model.First().LastName);
