using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedDepartmentsWithInstructors()
    {
        var instructor = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6)
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.Departments.AddRange(
            new Department
            {
                Name = "Mathematics",
                Budget = 100000,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = instructor.ID
            },
            new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = null
            }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        // Arrange
        SeedDepartmentsWithInstructors();

        // Act
        var result = _sut.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_WithNoDepartments_ReturnsEmptyList()
    {
        // Act
        var result = _sut.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    // --- Details ---

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        SeedDepartmentsWithInstructors();
        var dept = _context.Departments.First();

        // Act
        var result = _sut.Details(dept.DepartmentID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
        Assert.AreEqual(dept.Name, model.Name);
    }

