            Budget = dept.Budget,
            StartDate = dept.StartDate,
            InstructorID = dept.InstructorID,
            RowVersion = dept.RowVersion
        };

        // Act
        var result = _sut.Edit(updatedDept) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _sut.ModelState.AddModelError("Name", "Required");
        SeedDepartmentsWithInstructors();
        var dept = new Department { DepartmentID = 1 };

        // Act
        var result = _sut.Edit(dept) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Delete GET ---

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        SeedDepartmentsWithInstructors();
        var dept = _context.Departments.First();

        // Act
        var result = _sut.Delete(dept.DepartmentID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _sut.Delete(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- DeleteConfirmed ---

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        // Arrange
        SeedDepartmentsWithInstructors();
        var dept = _context.Departments.First();
        var initialCount = _context.Departments.Count();

        // Act
        var result = _sut.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Departments.Count());
    }
}

