using System;
using System.Linq;
using System.Net;
using System.Collections.Generic;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.Logging;
using Moq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private CoursesController _sut = null!;
    private Mock<IWebHostEnvironment> _envMock = null!;
    private Mock<ILogger<CoursesController>> _loggerMock = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns("/fake/wwwroot");
        _envMock.Setup(e => e.ContentRootPath).Returns("/fake/content");
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _sut = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedCourses()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        // Arrange
        SeedCourses();

        // Act
        var result = _sut.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_WithNoCourses_ReturnsEmptyList()
    {
        // Act
        var result = _sut.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    // --- Details ---

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsViewWithCourse()
    {
        // Arrange
        SeedCourses();

        // Act
        var result = _sut.Details(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual(1050, model.CourseID);
        Assert.AreEqual("Chemistry", model.Title);
    }

    [TestMethod]
    public void Details_WithInvalidId_ThrowsInvalidOperationException()
    {
        // The code uses .Single() which throws when no match exists
        Assert.ThrowsException<InvalidOperationException>(() => _sut.Details(9999));
    }

    // --- Create GET ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithNewCourse()
    {
        // Arrange
        SeedCourses();

        // Act
        var result = _sut.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
    }

    // --- Create POST ---

    [TestMethod]
    public void Create_Post_ValidCourse_SavesAndRedirects()
    {
        // Arrange
        SeedCourses();
        var course = new Course
        {
            CourseID = 2021,
            Title = "Composition",
            Credits = 3,
            DepartmentID = _context.Departments.First().DepartmentID
        };

        // Act
        var result = _sut.Create(course, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(3, _context.Courses.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        SeedCourses();
        _sut.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 9999 };

        // Act
        var result = _sut.Create(course, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Edit GET ---

    [TestMethod]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Edit(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_WithValidId_ReturnsViewWithCourse()
    {
        // Arrange
        SeedCourses();

        // Act
        var result = _sut.Edit(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual(1050, model.CourseID);
    }

    [TestMethod]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _sut.Edit(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Edit POST ---

    [TestMethod]
    public void Edit_Post_ValidCourse_UpdatesAndRedirects()
    {
        // Arrange
        SeedCourses();
        var course = _context.Courses.First();
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedCourse = new Course
        {
            CourseID = course.CourseID,
            Title = "Updated Chemistry",
            Credits = course.Credits,
            DepartmentID = course.DepartmentID
        };

        // Act
        var result = _sut.Edit(updatedCourse, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        SeedCourses();
        _sut.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050 };

        // Act
        var result = _sut.Edit(course, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Delete GET ---

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsViewWithCourse()
    {
        // Arrange
        SeedCourses();

        // Act
        var result = _sut.Delete(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual(1050, model.CourseID);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ThrowsInvalidOperationException()
    {
        // The code uses .Single() which throws when no match exists
        Assert.ThrowsException<InvalidOperationException>(() => _sut.Delete(9999));
    }

    // --- DeleteConfirmed ---

    [TestMethod]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        // Arrange
        SeedCourses();
        var initialCount = _context.Courses.Count();

        // Act
        var result = _sut.DeleteConfirmed(1050) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Courses.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_WithImagePath_StillDeletesCourse()
    {
        // Arrange
        SeedCourses();
        var course = _context.Courses.First();
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
        _context.SaveChanges();

        // Act - should not throw even though file doesn't exist
        var result = _sut.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }
}

