using System;
using System.Linq;
using System.Net;
using System.Collections.Generic;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedInstructorsAndCourses()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var instructor1 = new Instructor
        {
            LastName = "Harui",
            FirstMidName = "Roger",
            HireDate = new DateTime(1998, 7, 1),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Gowan 27" }
        };
        var instructor2 = new Instructor
        {
            LastName = "Kapoor",
            FirstMidName = "Candace",
            HireDate = new DateTime(2001, 1, 15),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.AddRange(instructor1, instructor2);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor1.ID, CourseID = 1050 });
        _context.SaveChanges();
    }

    // --- Index ---

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Arrange
        SeedInstructorsAndCourses();

        // Act
        var result = _sut.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_ShowsCourses()
    {
        // Arrange
        SeedInstructorsAndCourses();
        var instructor = _context.Instructors.First(i => i.LastName == "Harui");

        // Act
        var result = _sut.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
    }

    [TestMethod]
    public void Index_WithNoParams_ReturnsNullCourses()
    {
        // Arrange
        SeedInstructorsAndCourses();

        // Act
        var result = _sut.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNull(model.Courses);
    }

    // --- Details ---

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsAndCourses();
        var instructor = _context.Instructors.First();

        // Act
        var result = _sut.Details(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
    }

    [TestMethod]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _sut.Details(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Create GET ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithNewInstructor()
    {
        // Arrange
        SeedInstructorsAndCourses();

        // Act
        var result = _sut.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
        Assert.AreEqual(0, model.CourseAssignments.Count);
    }

    // --- Create POST ---

    [TestMethod]
    public void Create_Post_ValidInstructor_SavesAndRedirects()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };

        // Act
        var result = _sut.Create(instructor, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, _context.Instructors.Count());
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
    {
        // Arrange
        SeedInstructorsAndCourses();
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };
        var selectedCourses = new[] { "1050", "4022" };

        // Act
        var result = _sut.Create(instructor, selectedCourses) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        var savedInstructor = _context.Instructors.First(i => i.LastName == "NewInstructor");
        Assert.AreEqual(2, _context.CourseAssignments.Count(ca => ca.InstructorID == savedInstructor.ID));
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        SeedInstructorsAndCourses();
        _sut.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _sut.Create(instructor, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Edit GET ---

    [TestMethod]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Edit((int?)null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_WithValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsAndCourses();
        var instructor = _context.Instructors.First();

        // Act
        var result = _sut.Edit((int?)instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
    }

    // --- Delete GET ---

    [TestMethod]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        // Act
        var result = _sut.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_WithValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsAndCourses();
        var instructor = _context.Instructors.First();

        // Act
        var result = _sut.Delete(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
    }

    [TestMethod]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        // Act
        var result = _sut.Delete(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- DeleteConfirmed ---

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Arrange
        SeedInstructorsAndCourses();
        var instructor = _context.Instructors.First();
        var initialCount = _context.Instructors.Count();

        // Act
        var result = _sut.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        // Arrange
        SeedInstructorsAndCourses();
        var instructor = _context.Instructors.First();
        var dept = _context.Departments.First();
        dept.InstructorID = instructor.ID;
        _context.SaveChanges();

        // Act
        _sut.DeleteConfirmed(instructor.ID);

        // Assert
        var updatedDept = _context.Departments.First();
        Assert.IsNull(updatedDept.InstructorID);
    }
}

