using System;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new NotificationsController(_context);
        // Drain any leftover notifications from the static queue
        var drainService = new NotificationService();
        while (drainService.ReceiveNotification() != null) { }
        drainService.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain the queue to prevent cross-test contamination
        var drainService = new NotificationService();
        while (drainService.ReceiveNotification() != null) { }
        drainService.Dispose();
        _sut.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _sut.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void GetNotifications_WhenQueueEmpty_ReturnsSuccessWithZeroCount()
    {
        // Act
        var result = _sut.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        // Verify the anonymous object properties via reflection
        var successProp = json.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(json));

        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(json));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - send a notification via the service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");

        // Act
        var result = _sut.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);

        var successProp = json.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp!.GetValue(json));

        var countProp = json.GetType().GetProperty("count");
        Assert.AreEqual(1, countProp!.GetValue(json));

        service.Dispose();
    }

    [TestMethod]
    public void GetNotifications_LimitsToTenNotifications()
    {
        // Arrange - send 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _sut.GetNotifications();

        // Assert
        var json = result.Value;
        Assert.IsNotNull(json);
        var countProp = json.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp!.GetValue(json));

        service.Dispose();
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        // Act
        var result = _sut.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var successProp = json.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp!.GetValue(json));
    }
}

