using System;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsAllEntities()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - verify students were seeded
        Assert.AreEqual(8, context.Students.Count());
        Assert.IsTrue(context.Students.Any(s => s.LastName == "Alexander"));
        Assert.IsTrue(context.Students.Any(s => s.LastName == "Olivetto"));

        // Assert - verify instructors were seeded
        Assert.AreEqual(5, context.Instructors.Count());
        Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Abercrombie"));
        Assert.IsTrue(context.Instructors.Any(i => i.LastName == "Zheng"));

        // Assert - verify departments were seeded
        Assert.AreEqual(4, context.Departments.Count());
        Assert.IsTrue(context.Departments.Any(d => d.Name == "English"));
        Assert.IsTrue(context.Departments.Any(d => d.Name == "Mathematics"));
        Assert.IsTrue(context.Departments.Any(d => d.Name == "Engineering"));
        Assert.IsTrue(context.Departments.Any(d => d.Name == "Economics"));

        // Assert - verify courses were seeded
        Assert.AreEqual(7, context.Courses.Count());
        Assert.IsTrue(context.Courses.Any(c => c.Title == "Chemistry" && c.CourseID == 1050));
        Assert.IsTrue(context.Courses.Any(c => c.Title == "Literature" && c.CourseID == 2042));

        // Assert - verify office assignments were seeded
        Assert.AreEqual(3, context.OfficeAssignments.Count());

        // Assert - verify course assignments were seeded
        Assert.AreEqual(8, context.CourseAssignments.Count());

        // Assert - verify enrollments were seeded
        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);
        var studentCountBefore = context.Students.Count();
        var courseCountBefore = context.Courses.Count();

        // Act - initialize again
        DbInitializer.Initialize(context);

        // Assert - counts should not change
        Assert.AreEqual(studentCountBefore, context.Students.Count());
        Assert.AreEqual(courseCountBefore, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_SetsCorrectEnrollmentDates()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var carson = context.Students.Single(s => s.LastName == "Alexander");
        Assert.AreEqual(DateTime.Parse("2010-09-01"), carson.EnrollmentDate);

        var nino = context.Students.Single(s => s.LastName == "Olivetto");
        Assert.AreEqual(DateTime.Parse("2005-09-01"), nino.EnrollmentDate);
    }

    [TestMethod]
    public void Initialize_SetsCorrectCourseCredits()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var chemistry = context.Courses.Single(c => c.CourseID == 1050);
        Assert.AreEqual(3, chemistry.Credits);
        Assert.AreEqual("Chemistry", chemistry.Title);

        var calculus = context.Courses.Single(c => c.CourseID == 1045);
        Assert.AreEqual(4, calculus.Credits);
        Assert.AreEqual("Calculus", calculus.Title);
    }

    [TestMethod]
    public void Initialize_SetsCorrectGrades()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - Carson Alexander's Chemistry enrollment has Grade A
        var carson = context.Students.Single(s => s.LastName == "Alexander");
        var enrollment = context.Enrollments.Single(
            e => e.StudentID == carson.ID && e.CourseID == 1050);
        Assert.AreEqual(Grade.A, enrollment.Grade);

        // Arturo Anand's Chemistry enrollment has no grade
        var arturo = context.Students.Single(s => s.LastName == "Anand");
        var noGradeEnrollment = context.Enrollments.Single(
            e => e.StudentID == arturo.ID && e.CourseID == 1050);
        Assert.IsNull(noGradeEnrollment.Grade);
    }

    [TestMethod]
    public void Initialize_SetsDepartmentBudgets()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var english = context.Departments.Single(d => d.Name == "English");
        Assert.AreEqual(350000m, english.Budget);

        var math = context.Departments.Single(d => d.Name == "Mathematics");
        Assert.AreEqual(100000m, math.Budget);
    }

    [TestMethod]
    public void Initialize_LinksCoursesToDepartments()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - Chemistry should be in Engineering department
        var engineering = context.Departments.Single(d => d.Name == "Engineering");
        var chemistry = context.Courses.Single(c => c.CourseID == 1050);
        Assert.AreEqual(engineering.DepartmentID, chemistry.DepartmentID);
    }

    [TestMethod]
    public void Initialize_SetsOfficeAssignments()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var fakhouri = context.Instructors.Single(i => i.LastName == "Fakhouri");
        var office = context.OfficeAssignments.Single(o => o.InstructorID == fakhouri.ID);
        Assert.AreEqual("Smith 17", office.Location);
    }
}

